/// <summary>
/// Extension class for <c>CustVendVoucher</c> class.
/// </summary>
[ExtensionOf(classStr(CustVendVoucher))]
final class FWFVendInvoiceCustVendVoucher_Extension
{
    private FWFVendInvoiceDate vendInvoiceDate;

}

Method.Source:
/// <summary>
/// Gets/Sets the <c>FWFVendInvoiceDate</c>.
/// </summary>
/// <param name = "_vendInvoiceDate">The <c>FWFVendInvoiceDate</c> to set; optional</param>
/// <returns>The <c>FWFVendInvoiceDate</c>.</returns>
public FWFVendInvoiceDate parmFWFVendInvoiceDate(FWFVendInvoiceDate _vendInvoiceDate = vendInvoiceDate)
{
    vendInvoiceDate = _vendInvoiceDate;

    return vendInvoiceDate;
}

/// <summary>
/// Updates the <c>CustVendTrans</c> map.
/// </summary>
/// <param name="custVendTrans">The map that contains the value of the vendor transaction or customer transaction.</param>
/// <param name="_ledgerPostingJournal">The ledger posting journal to use for ledger posting.</param>
/// <param name="_useSubLedger">A Boolean value that indicates whether the subledger is being used; optional.</param>
protected void initCustVendTrans(
    CustVendTrans custVendTrans,
    LedgerVoucher _ledgerPostingJournal,
    boolean _useSubLedger)
{
    next initCustVendTrans(custVendTrans, _ledgerPostingJournal, _useSubLedger);

    if (custVendTrans.TableId == tableNum(VendTrans))
    {
        VendTrans vendTrans = custVendTrans;

        if (!vendTrans.FWFVendInvoiceDate && this.parmFWFVendInvoiceDate())
        {
            vendTrans.FWFVendInvoiceDate = this.parmFWFVendInvoiceDate();
        }
    }
}
